import{_ as a,o as i,c as n,ag as p}from"./chunks/framework.oqSrIbQK.js";const r=JSON.parse('{"title":"生产环境 MySQL 不暴露公网时，本地如何安全连接数据库","description":"","frontmatter":{"title":"生产环境 MySQL 不暴露公网时，本地如何安全连接数据库","date":"2026-04-24T00:00:00.000Z","tags":["MySQL","SSH Tunnel","服务器安全","部署安全"],"categories":["部署运维"]},"headers":[],"relativePath":"posts/云开发/生产环境 MySQL 不暴露公网时，本地如何安全连接数据库.md","filePath":"posts/云开发/生产环境 MySQL 不暴露公网时，本地如何安全连接数据库.md","lastUpdated":1777040623000}'),e={name:"posts/云开发/生产环境 MySQL 不暴露公网时，本地如何安全连接数据库.md"};function t(l,s,h,d,c,o){return i(),n("div",null,[...s[0]||(s[0]=[p(`<h2 id="一、整体实现思路" tabindex="-1">一、整体实现思路 <a class="header-anchor" href="#一、整体实现思路" aria-label="Permalink to &quot;一、整体实现思路&quot;">​</a></h2><p>生产环境数据库<strong>不要直接开放 3306 到公网</strong>，否则容易被扫描、爆破、撞库。</p><p>正确做法是：</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>本地电脑</span></span>
<span class="line"><span>  ↓ SSH 加密连接</span></span>
<span class="line"><span>服务器 SSH</span></span>
<span class="line"><span>  ↓ 转发到服务器本机</span></span>
<span class="line"><span>MySQL 127.0.0.1:3306</span></span></code></pre></div><p>也就是：</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>本地连接 127.0.0.1:13306</span></span>
<span class="line"><span>实际访问 服务器内部 127.0.0.1:3306</span></span></code></pre></div><p>这样 MySQL 对公网不可见，但你本地仍然可以安全连接。</p><hr><h2 id="二、服务器侧配置-mysql-只监听本机" tabindex="-1">二、服务器侧配置 MySQL 只监听本机 <a class="header-anchor" href="#二、服务器侧配置-mysql-只监听本机" aria-label="Permalink to &quot;二、服务器侧配置 MySQL 只监听本机&quot;">​</a></h2><p>找到 MySQL 配置文件，常见位置：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/etc/mysql/mysql.conf.d/mysqld.cnf</span></span></code></pre></div><p>或：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/etc/my.cnf</span></span></code></pre></div><p>修改：</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 只允许服务器本机访问 MySQL，不监听公网网卡</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">bind-address</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 127.0.0.1</span></span></code></pre></div><p>然后重启 MySQL：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mysql</span></span></code></pre></div><p>检查监听状态：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3306</span></span></code></pre></div><p>理想结果类似：</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>127.0.0.1:3306</span></span></code></pre></div><p>不要是：</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0.0.0.0:3306</span></span></code></pre></div><p>也不要是：</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>公网IP:3306</span></span></code></pre></div><hr><h2 id="三、防火墙关闭-mysql-公网端口" tabindex="-1">三、防火墙关闭 MySQL 公网端口 <a class="header-anchor" href="#三、防火墙关闭-mysql-公网端口" aria-label="Permalink to &quot;三、防火墙关闭 MySQL 公网端口&quot;">​</a></h2><p>如果你用的是 <code>ufw</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 禁止公网访问 MySQL</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ufw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deny</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3306</span></span></code></pre></div><p>只保留必要端口：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ufw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> allow</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 22</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ufw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> allow</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 80</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ufw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> allow</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 443</span></span></code></pre></div><p>查看状态：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ufw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p>如果你用的是云服务器安全组，也要在云厂商控制台关闭 <code>3306</code> 入站规则。</p><hr><h2 id="四、本地电脑通过-ssh-隧道连接-mysql" tabindex="-1">四、本地电脑通过 SSH 隧道连接 MySQL <a class="header-anchor" href="#四、本地电脑通过-ssh-隧道连接-mysql" aria-label="Permalink to &quot;四、本地电脑通过 SSH 隧道连接 MySQL&quot;">​</a></h2><p>在你本地电脑执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 将本地 13306 端口转发到服务器内部的 MySQL 3306</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 13306:127.0.0.1:3306</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@你的服务器公网IP</span></span></code></pre></div><p>保持这个终端不要关闭。</p><p>然后你本地数据库客户端连接：</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host: 127.0.0.1</span></span>
<span class="line"><span>Port: 13306</span></span>
<span class="line"><span>User: 数据库用户名</span></span>
<span class="line"><span>Password: 数据库密码</span></span>
<span class="line"><span>Database: 数据库名</span></span></code></pre></div><p>注意：这里不是连服务器公网 IP，而是连你自己电脑的：</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>127.0.0.1:13306</span></span></code></pre></div><hr><h2 id="五、navicat-datagrip-dbeaver-配置方式" tabindex="-1">五、Navicat / DataGrip / DBeaver 配置方式 <a class="header-anchor" href="#五、navicat-datagrip-dbeaver-配置方式" aria-label="Permalink to &quot;五、Navicat / DataGrip / DBeaver 配置方式&quot;">​</a></h2><p>如果你用数据库客户端，一般都有 SSH Tunnel 配置。</p><h3 id="数据库连接配置" tabindex="-1">数据库连接配置 <a class="header-anchor" href="#数据库连接配置" aria-label="Permalink to &quot;数据库连接配置&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host: 127.0.0.1</span></span>
<span class="line"><span>Port: 3306</span></span>
<span class="line"><span>User: 数据库用户名</span></span>
<span class="line"><span>Password: 数据库密码</span></span></code></pre></div><h3 id="ssh-隧道配置" tabindex="-1">SSH 隧道配置 <a class="header-anchor" href="#ssh-隧道配置" aria-label="Permalink to &quot;SSH 隧道配置&quot;">​</a></h3><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SSH Host: 服务器公网 IP</span></span>
<span class="line"><span>SSH Port: 22</span></span>
<span class="line"><span>SSH User: root 或 deploy 用户</span></span>
<span class="line"><span>SSH Password / SSH Key: 你的 SSH 登录凭据</span></span></code></pre></div><p>客户端会自动帮你完成：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 本地端口:127.0.0.1:3306</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 服务器</span></span></code></pre></div><hr><h2 id="六、项目-env-production-推荐配置" tabindex="-1">六、项目 <code>.env.production</code> 推荐配置 <a class="header-anchor" href="#六、项目-env-production-推荐配置" aria-label="Permalink to &quot;六、项目 \`.env.production\` 推荐配置&quot;">​</a></h2><p>如果应用和 MySQL 在同一台服务器上，生产环境可以这样：</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 应用部署在服务器本机时，直接连接服务器内部 MySQL</span></span>
<span class="line"><span>DATABASE_HOST=127.0.0.1</span></span>
<span class="line"><span>DATABASE_PORT=3306</span></span>
<span class="line"><span>DATABASE_USER=your_user</span></span>
<span class="line"><span>DATABASE_PASSWORD=your_password</span></span>
<span class="line"><span>DATABASE_NAME=your_db</span></span></code></pre></div><p>不要写成：</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DATABASE_HOST=服务器公网IP</span></span>
<span class="line"><span>DATABASE_PORT=3306</span></span></code></pre></div><hr><h2 id="七、最简安全方案" tabindex="-1">七、最简安全方案 <a class="header-anchor" href="#七、最简安全方案" aria-label="Permalink to &quot;七、最简安全方案&quot;">​</a></h2><p>你的场景可以直接按这个方案做：</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MySQL:</span></span>
<span class="line"><span>  bind-address = 127.0.0.1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>服务器防火墙:</span></span>
<span class="line"><span>  不开放 3306</span></span>
<span class="line"><span>  只开放 22 / 80 / 443</span></span>
<span class="line"><span></span></span>
<span class="line"><span>本地连接:</span></span>
<span class="line"><span>  ssh -L 13306:127.0.0.1:3306 root@服务器公网IP</span></span>
<span class="line"><span></span></span>
<span class="line"><span>数据库客户端:</span></span>
<span class="line"><span>  连接 127.0.0.1:13306</span></span></code></pre></div><hr><h2 id="八、最终检查清单" tabindex="-1">八、最终检查清单 <a class="header-anchor" href="#八、最终检查清单" aria-label="Permalink to &quot;八、最终检查清单&quot;">​</a></h2><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ ] MySQL 监听地址是 127.0.0.1:3306</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ ] 云服务器安全组没有开放 3306</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ ] Linux 防火墙没有开放 3306</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ ] 本地通过 SSH Tunnel 连接数据库</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ ] 生产应用通过 127.0.0.1:3306 访问 MySQL</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ ] 数据库密码、JWT、微信、LLM 等密钥已经轮换</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ ] </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`.env.prod\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 不再提交到代码仓库</span></span></code></pre></div><p>结论：<strong>数据库不暴露公网，不影响本地连接；本地通过 SSH 隧道连，是个人项目和小团队部署中最推荐的方式。</strong></p>`,66)])])}const g=a(e,[["render",t]]);export{r as __pageData,g as default};
